/**
 * Marked.js - 轻量级 Markdown 解析器
 * 如果本地文件加载失败，会自动从 CDN 加载
 */

// 检查是否已有 marked 对象
if (typeof window.marked === 'undefined') {
    console.log('Loading marked from CDN...');
    
    // 动态创建 script 标签从 CDN 加载
    const script = document.createElement('script');
    script.src = 'https://cdn.jsdelivr.net/npm/marked/marked.min.js';
    script.onload = function() {
        console.log('Marked loaded from CDN successfully');
    };
    document.head.appendChild(script);
}

// 配置 marked 选项
window.markedOptions = {
    breaks: true,        // 启用换行符转换
    gfm: true,          // GitHub Flavored Markdown
    headerIds: true,    // 添加标题 ID
    mangle: false,      // 不转义 HTML
    sanitize: false     // 允许 HTML 标签
};
